import hashlib
import random

class General:
 def __init__(self, name):
 self.name = name
 self.messages = {}

 def send_message(self, message):
 signature = hashlib.sha256(message.encode()).hexdigest()
 self.messages[message] = signature

 def verify_message(self, message, signature):
 return self.messages.get(message) == signature

# Create generals and simulate message exchange
num_generals = 5
messages = [random.choice(['Attack', 'Retreat']) for _ in range(num_generals)]
generals = [General(f'General {i}') for i in range(num_generals)]

for i, general in enumerate(generals):
 general.send_message(messages[i])

for i, general in enumerate(generals):
 for j, other_general in enumerate(generals):
 if i != j:
 message = messages[j]
 signature = generals[j].messages[message]
 if general.verify_message(message, signature):
 print(f'{general.name} verified {message} from {other_general.name}')

#include <stdio.h>
#include <string.h>
#include <openssl/sha.h>

#define HASH_SIZE 256

void proof_of_work(const char* block_data, unsigned int difficulty) {
 unsigned char hash[HASH_SIZE];
 char* nonce = malloc(10);
 sprintf(nonce, "%d", 0);

 while (1) {
 char* block_hash = malloc(HASH_SIZE);
 sprintf(block_hash, "%s%s", block_data, nonce);
 SHA256_CTX sha256;
 SHA256_Init(&sha256);
 SHA256_Update(&sha256, block_hash, strlen(block_hash));
 SHA256_Final(hash, &sha256);

 int leading_zeros = 0;
 for (int i = 0; i < HASH_SIZE; i++) {
 if (hash[i] == 0) {
 leading_zeros++;
 } else {
 break;
 }
 }

 if (leading_zeros >= difficulty) {
 printf("Block hash: %s\n", block_hash);
 break;
 }

 free(block_hash);
 sprintf(nonce, "%d", atoi(nonce) + 1);
 }

 free(nonce);
}

int main() {
 const char* block_data = "Transaction data";
 unsigned int difficulty = 4;
 proof_of_work(block_data, difficulty);
 return 0;
}
